import 'package:dio/dio.dart';import 'package:flutter_test/flutter_test.dart';import 'package:meme_arena/core/config/api_config.dart';import 'package:meme_arena/core/config/content_url_resolver.dart';import 'package:meme_arena/core/errors/app_error.dart';import 'package:meme_arena/features/models.dart';
void main(){test('base URL config',(){expect(ApiConfig().baseUrl,'http://10.0.2.2:8080');expect(ApiConfig(baseUrl:'http://x/').baseUrl,'http://x');});test('content URL resolver',(){final r=ContentUrlResolver(ApiConfig(baseUrl:'http://api'));expect(r.resolve('/api/v1/media/1/content'),'http://api/api/v1/media/1/content');expect(r.resolve('https://cdn/x'),'https://cdn/x');});test('error response parsing',(){final e=AppError.fromDio(DioException(requestOptions:RequestOptions(),response:Response(requestOptions:RequestOptions(),statusCode:400,data:{'code':'BAD','message':'Ошибка','fieldErrors':{'title':'required'}})));expect(e.message,'Ошибка');expect(e.fieldErrors['title'],'required');});test('nickname validation',(){expect(validateNickname('ab'),isNotNull);expect(validateNickname('valid_ник'),isNull);});test('leaderboard period mapping',(){expect(periodCode(2),'ALL_TIME');});}
